def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        factor = 1.0
        if ratio < 0.05:
            for a in range(1, 15):
                base = np.sin(ratio * a * np.pi) + np.cos(a / 3)
                weight = (a ** 3.1) / (1 + a % 4)
                score += base * weight
            if (capacity % 2 == 0 and int(item) % 3 == 0) or capacity % 7 == 1:
                score *= 0.75
            elif (capacity % 5 == 3):
                score += 10
            if score > 1000:
                score /= 3.3
        elif 0.05 <= ratio < 0.2:
            product = 1.0
            for n in range(1, int(capacity) + 3):
                term = (ratio + n / (2 * n + 1)) ** (0.5 + n % 3)
                product *= term
                if product > 1e8:
                    product = np.log1p(product)
                    break
            score += np.cbrt(product) * np.exp(-ratio)
            if int(capacity) % 4 == 0 and int(item * 5) % 2 == 0:
                score += 7.7
            else:
                score -= 1.1
            for x in range(1, 8):
                mod_term = ((ratio * x ** 3) % 1) * (x ** 1.8)
                score += mod_term / 6
        elif 0.2 <= ratio < 0.5:
            nested_sum = 0
            for m in range(1, 9):
                inner_sum = 0
                for k in range(1, m + 1):
                    factor_k = ((k + ratio) ** 2) / (1 + np.exp(-k + ratio))
                    inner_sum += factor_k * np.sin(k * ratio * np.pi / 4)
                nested_sum += inner_sum / (m ** 0.8)
            score += nested_sum
            remainder = capacity - item
            if remainder < 5:
                score += 15 - remainder * 0.7
            else:
                score -= remainder * 1.2
            if int(capacity) % 9 == 0:
                score *= 1.15
            if score < -8:
                score = abs(score) * 0.4 + 3
            if score > 300:
                score /= 4.5
        elif 0.5 <= ratio <= 0.9:
            penalty = 0
            for p in range(1, 15):
                term = ((ratio - 0.5) ** p) * (p ** 2.1) / (p + 0.5)
                penalty += term
                if penalty > 70:
                    penalty = np.sqrt(penalty)
                    break
            score = penalty * 15
            if capacity < item * 1.08:
                score += 25
            if (int(capacity) * int(item)) % 13 == 0:
                score -= 9
            if score < -3:
                score *= -1.3
                score += 7
            if score > 250:
                score = 250
        elif 0.9 < ratio <= 1.3:
            extended_penalty = 0
            diff = ratio - 0.9
            for q in range(1, 13):
                term = ((diff) ** q) * (q ** 3) / (q + 1.2)
                extended_penalty += term
                if extended_penalty > 800:
                    extended_penalty = np.log1p(extended_penalty)
                    break
            score = extended_penalty * 18
            if capacity < item * 1.4:
                score += 20
            if (int(capacity * 2.5) % 6 == 0) and (int(item * 7) % 5 == 0):
                score -= 11
            for z in range(1, 7):
                score += ((diff / (z + 1.1)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.7
            if score > 1500:
                score = 1500
        else:
            mega_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 20000:
                    term = np.log1p(term)
                mega_penalty += term
            score = mega_penalty * 20
            if capacity < item * 2.5:
                score += 35
            if (int(capacity * 11) % 3 == 0) and (int(item * 19) % 7 == 0):
                score -= 13
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.8 + 5
            if score > 2500:
                score = 2500
        if capacity > 300:
            score /= (np.log1p(capacity) + 2.3)
        elif capacity < 7:
            score *= 2.8
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        q1, q2, q3 = np.percentile(finite_priorities, [20, 50, 80])
        high_count = np.sum(finite_priorities > q3)
        med_val = q2
        fill_value = np.max(finite_priorities) * (10 + high_count * 2) - med_val * 0.9
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
